+    local procedure UpdateHeaderStatusOnInsert()
+    var
+        LocalServHeader: Record "Service Header";
+        LocalServItemLine: Record "Service Item Line";
+        RepairStatus: Record "Repair Status";
+        MinRepairStatusPriority: Integer;
+        MinRepairStatusCode: Code[10];
+        MinLineno: Integer;
+    begin
+        GetServHeader();
+        if ServHeader."Document Type" <> ServHeader."Document Type"::Order then
+            exit;
+
+        LocalServItemLine.Reset();
+        LocalServItemLine.SetRange("Document Type", "Document Type");
+        LocalServItemLine.SetRange("Document No.", "Document No.");
+        LocalServItemLine.SetFilter("Line No.", '<>%1', 0);
+        
+        if not LocalServItemLine.Find('-') then
+            exit;
+
+        MinRepairStatusPriority := 999999;
+        MinRepairStatusCode := '';
+        MinLineno := 0;
+
+        repeat
+            if LocalServItemLine."Repair Status Code" <> '' then begin
+                if RepairStatus.Get(LocalServItemLine."Repair Status Code") then begin
+                    if RepairStatus.Priority < MinRepairStatusPriority then begin
+                        MinRepairStatusPriority := RepairStatus.Priority;
+                        MinRepairStatusCode := LocalServItemLine."Repair Status Code";
+                        MinLineno := LocalServItemLine."Line No.";
+                    end;
+                end;
+            end;
+        until LocalServItemLine.Next() = 0;
+
+        if MinRepairStatusCode <> '' then begin
+            LocalServHeader.Get("Document Type", "Document No.");
+            if RepairStatus.Get(MinRepairStatusCode) then begin
+                if LocalServHeader.Status <> RepairStatus."Service Order Status" then begin
+                    LocalServHeader.SetValidatingFromLines(true);
+                    if LocalServHeader."Finishing Date" = 0D then
+                        LocalServHeader.Validate("Finishing Date", LocalServItemLine."Finishing Date");
+                    LocalServHeader.Validate(Status, RepairStatus."Service Order Status");
+                    if not (LocalServHeader.Status = LocalServHeader.Status::Finished) then begin
+                        LocalServHeader."Finishing Date" := 0D;
+                        LocalServHeader."Finishing Time" := 0T;
+                        LocalServHeader."Service Time (Hours)" := 0;
+                    end;
+                    LocalServHeader.Modify();
+                end;
+            end;
+        end;
+    end;
+
